// src/controllers/UserController.js
import UserService from '../services/UserService';

const UserController = {
  async loadUsers(setUsers, setLoading, toast) {
    setLoading(true);
    try {
      const data = await UserService.getAllUsers();
      setUsers(data);
    } catch (error) {
      toast.error('Erro ao carregar usuários.');
    } finally {
      setLoading(false);
    }
  },

  async handleCreate(formData, setUsers, closeModal, toast) {
    try {
      const newUser = await UserService.createUser(formData);
      setUsers(prev => [newUser, ...prev]);
      toast.success('Usuário criado com sucesso!');
      closeModal();
    } catch (error) {
      toast.error(error.message || 'Erro ao criar usuário.');
    }
  },

  async handleUpdate(id, formData, setUsers, closeModal, toast) {
    try {
      const updated = await UserService.updateUser(id, formData);
      setUsers(prev => prev.map(u => (u.id === id ? updated : u)));
      toast.success('Usuário atualizado!');
      closeModal();
    } catch (error) {
      toast.error(error.message || 'Erro ao atualizar usuário.');
    }
  },

  async handleDelete(id, setUsers, toast) {
    try {
      await UserService.deleteUser(id);
      setUsers(prev => prev.filter(u => u.id !== id));
      toast.success('Usuário removido.');
    } catch (error) {
      toast.error(error.message || 'Erro ao remover usuário.');
    }
  }
};

export default UserController;
